import express from "express";
import path from "path";
import dotenv from "dotenv";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";

// Load environment variables
dotenv.config();

const app = express();
const PORT = 3000;

app.use(express.json());

// Initialize Gemini SDK with helper for optional client API keys
const geminiApiKey = process.env.GEMINI_API_KEY;
const defaultAi = geminiApiKey 
  ? new GoogleGenAI({
      apiKey: geminiApiKey,
      httpOptions: {
        headers: {
          'User-Agent': 'aistudio-build',
        }
      }
    })
  : null;

function getAiClient(req: express.Request): GoogleGenAI | null {
  const clientKey = req.headers["x-gemini-key"] as string;
  if (clientKey && clientKey.trim()) {
    try {
      return new GoogleGenAI({
        apiKey: clientKey.trim(),
        httpOptions: {
          headers: {
            'User-Agent': 'aistudio-build',
          }
        }
      });
    } catch (e) {
      console.error("Failed to compile user custom GoogleGenAI instance:", e);
    }
  }
  return defaultAi;
}

// Mock database for Global Leaderboard with in-memory state
// We populate it with competitive virtual futurologists to gamify the experience
const initialLeaderboard = [
  { id: "1", name: "Helena Kepler", level: 14, xp: 14200, predictionsCorrect: 29, badge: "Oráculo de Bronze" },
  { id: "2", name: "Arthur C. Clarke", level: 12, xp: 12100, predictionsCorrect: 24, badge: "Viajante do Tempo" },
  { id: "3", name: "Niels Bohr", level: 11, xp: 11050, predictionsCorrect: 22, badge: "Analista Quântico" },
  { id: "4", name: "Alan Turing", level: 9, xp: 9500, predictionsCorrect: 18, badge: "Calculador Lógico" },
  { id: "5", name: "Ada Lovelace", level: 8, xp: 8200, predictionsCorrect: 15, badge: "Pioneira Digital" }
];

let globalLeaderboard = [...initialLeaderboard];

// API: Get leaderboard
app.get("/api/leaderboard", (req, res) => {
  res.json(globalLeaderboard);
});

// API: Submit user score to leaderboard dynamically
app.post("/api/leaderboard/update", (req, res) => {
  const { name, level, xp, predictionsCorrect, badge } = req.body;
  if (!name) {
    return res.status(400).json({ error: "Missing name" });
  }

  // Check if user already exists
  const existingIndex = globalLeaderboard.findIndex(u => u.name.toLowerCase() === name.toLowerCase());
  if (existingIndex !== -1) {
    globalLeaderboard[existingIndex] = {
      ...globalLeaderboard[existingIndex],
      level: Math.max(globalLeaderboard[existingIndex].level, level || 1),
      xp: Math.max(globalLeaderboard[existingIndex].xp, xp || 0),
      predictionsCorrect: Math.max(globalLeaderboard[existingIndex].predictionsCorrect, predictionsCorrect || 0),
      badge: badge || globalLeaderboard[existingIndex].badge
    };
  } else {
    globalLeaderboard.push({
      id: String(globalLeaderboard.length + 1),
      name,
      level: level || 1,
      xp: xp || 0,
      predictionsCorrect: predictionsCorrect || 0,
      badge: badge || "Novato"
    });
  }

  // Sort leaderboard by XP descending
  globalLeaderboard.sort((a, b) => b.xp - a.xp);
  res.json(globalLeaderboard);
});

// API: Reset leaderboard if needed
app.post("/api/leaderboard/reset", (req, res) => {
  globalLeaderboard = [...initialLeaderboard];
  res.json(globalLeaderboard);
});

// API: Health status
